sql:
SELECT ep.episode_id, ep.total_reward
FROM episodes ep
INNER JOIN experiments e ON ep.experiment_id = e.experiment_id;

external_knowledge:
- 'finished or botched trials' refers to experiments with statuses 'completed' or 'failed'.;
- 'behind them' refers to the researchers who conducted the experiments. The researchers are identified by their roles as 'researcher'.;
- 'settings' refers to the environment in which the experiments were performed. 'Methods' refer to the reinforcement learning algorithms used.

sql:
SELECT e.experiment_name, al.access_type
FROM experiments e
JOIN access_logs al ON e.experiment_id = al.experiment_id;

SELECT e.experiment_name, COUNT(DISTINCT e.algorithm_id) AS algorithm_count
FROM experiments AS e
GROUP BY e.experiment_id;

SELECT episodes.episode_number, experiments.experiment_name
FROM episodes
JOIN experiments ON episodes.experiment_id = experiments.experiment_id;

SELECT episode_id, episode_number, COUNT(action) AS num_actions
FROM timesteps
GROUP BY episode_id;
